void MonsterG1049::selectPatrolTargetPos()
{
///<<< BEGIN WRITING YOUR CODE selectPatrolTargetPos
	if (!this->patrolTargetPos.isInvalid() || Server::Instance()->getWorld()->getClosestPlayerIgnoreYPos(this->entity->position, 160) == nullptr)
		return;

	if (patrolType == 1)
	{
		if (this->entity->position == this->entity->getBornPos())
		{
			auto yaw = this->entity->getBornYaw();
			float incX = -Math::Sin(yaw * Math::DEG2RAD)*patrolDistanceOnce;
			float incZ = Math::Cos(yaw *Math::DEG2RAD)*patrolDistanceOnce;

			Vector3 toPos = this->entity->getBornPos();

			toPos.x += (int)incX;
			toPos.z += (int)incZ;

			patrolTargetPos = toPos;
		}
		else
		{
			patrolTargetPos = this->entity->getBornPos();
		}
	}
	else if(patrolType == 2)
	{
		float nextYaw = 0;
		Vector3 toPos = this->entity->position;
		if (this->haveCollisionAtLastPatrol)
		{
			//toPos = this->entity->getBornPos();
			nextYaw = this->entity->rotationYaw + 90;
		}
		else
		{
			nextYaw = NewRandom::Instance()->random(20, 90);
			nextYaw += this->entity->rotationYaw;
		}


			if (nextYaw > 180)
				nextYaw = 360 - nextYaw;
			else if (nextYaw < -180)
				nextYaw = 360 + nextYaw;

		
			int findCount = 0;
			while (true)
			{
				toPos = this->entity->position;

				float incX = -Math::Sin(nextYaw * Math::DEG2RAD)*patrolDistanceOnce;
				float incZ = Math::Cos(nextYaw *Math::DEG2RAD)*patrolDistanceOnce;

				toPos.x += incX;
				toPos.z += incZ;

				if (toPos.distanceTo(this->entity->getBornPos()) > patrolRange)
				{
					nextYaw += 10;
					if (nextYaw >= 180)
						nextYaw = -180;

					if (findCount++ >= 36)
					{
						toPos = this->entity->getBornPos();
						break;
					}

				}
				else
					break;
			}
		
		patrolTargetPos = toPos;
	}

///<<< END WRITING YOUR CODE
}

