void MonsterG1049::notifyAttacked(BLOCKMAN::EntityPlayer *ennemy)
{
	if (!enterAttack)
	{
		this->ennemy = ennemy;
		this->ennemyId = ennemy->entityId;
		hasBeAttacked = true;
		lastBeAttackedTime = LORD::Root::Instance()->getCurrentTime();
	}
	else if (hasBeAttacked && ennemy->entityId == this->ennemyId)
	{
		lastBeAttackedTime = LORD::Root::Instance()->getCurrentTime();
	}
}

bool MonsterG1049::reciveGatherEvent(const BLOCKMAN::BlockPos&pGatherCenter, int range)
{
	if (this->entity->position.distanceTo(pGatherCenter) < range)
	{
		this->inResponseGatherEvent = true;
		this->patrolPosBeforAttack = this->entity->position;
		this->gatherPosition = pGatherCenter;
	}
	return true;
}

bool MonsterG1049::reciveStopGatherEvent() 
{
	this->inResponseGatherEvent = false;
	return true;
}

void MonsterG1049::init(BLOCKMAN::MonsterSetting *pSetting, BLOCKMAN::EntityCreature *entity_)
{

	this->entity = entity_;

	alertTime = pSetting->alertTime*1000;
	hasBeAttacked = false;
	jumpSearchEnemyFrames = 0;
	patrolInterval = pSetting->patrolCD*1000;
	patrolRange = (int)pSetting->patrolDistance;
	patrolType = pSetting->patrolType;
	patrolDistanceOnce = pSetting->patrolDistanceOnce;

	searchEnemyIntervalFrames = kSearchEnemyIntervalFrames;

	viewRange = pSetting->viewRange;
	viewDegree = pSetting->viewDegree;
	attackRange = pSetting->attackDistance;
	attackCD = pSetting->attackCd*1000;
	isFlyEntity = pSetting->canFly;
	pursueDistance = pSetting->pursueDistance;
	fallowEnemySpeedAddtion = pSetting->moveSpeedAddition;
	normalMoveSpeedAddtion = (float)pSetting->moveSpeed;
	hasTogaterSkill = pSetting->canTogether;
	gatherRange = (int)pSetting->togetherRange;

	patrolPosBeforAttack.invalid();

	if (patrolDistanceOnce > patrolRange)
		patrolDistanceOnce = (float)(patrolRange -1);

	if (!pSetting->canTogether) 
	{
		subscriptionReciveGatherEvent = BLOCKMAN::LOGIC::G1049UseGatherSkillEvent::subscribe(
			std::bind(&MonsterG1049::reciveGatherEvent, this, std::placeholders::_1, std::placeholders::_2));

		subscriptionStopGatherEvent = BLOCKMAN::LOGIC::G1049UseStopGatherEvent::subscribe(
			std::bind(&MonsterG1049::reciveStopGatherEvent, this));
	}
}
